import moment from "moment";
import React, { useEffect, useState } from "react";
import Layout from "../components/shared/Layout/Layout";
import API from "../services/API";
import { useSelector } from "react-redux";

const bloodGroups = ["O+", "O-", "A+", "A-", "B+", "B-", "AB+", "AB-"];

const Donation = () => {
  const { user } = useSelector((state) => state.auth);
  const [data, setData] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [bloodGroup, setBloodGroup] = useState("");
  const [quantity, setQuantity] = useState("");
  const [orgEmail, setOrgEmail] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const getDonations = async () => {
    try {
      const { data } = await API.post("/inventory/get-inventory-hospital", {
        filters: { inventoryType: "in", donar: user?._id },
      });
      if (data?.success) setData(data?.inventory);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getDonations();
  }, []);

  const handleSubmit = async () => {
    try {
      if (!bloodGroup || !quantity || !orgEmail) {
        return alert("Please fill all fields");
      }
      setSubmitting(true);
      const { data } = await API.post("/inventory/create-inventory", {
        email: user?.email,
        organisation: orgEmail,
        inventoryType: "in",
        bloodGroup,
        quantity,
        donar: user?._id,
      });
      if (data?.success) {
        alert("Donation recorded successfully! Thank you 🩸");
        setShowForm(false);
        setBloodGroup("");
        setQuantity("");
        setOrgEmail("");
        getDonations();
      }
    } catch (error) {
      alert(error?.response?.data?.message || "Something went wrong");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Layout>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        .don-page { font-family: 'DM Sans', sans-serif; }
        .don-top { display: flex; align-items: center; justify-content: space-between; margin-bottom: 28px; flex-wrap: wrap; gap: 12px; }
        .don-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 700; color: #fff; }
        .don-title span { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
        .don-subtitle { font-size: 14px; color: rgba(255,255,255,0.4); margin-top: 4px; }
        .don-add-btn {
          padding: 11px 22px; border-radius: 12px; border: none; cursor: pointer;
          background: linear-gradient(135deg, #9333ea, #ec4899);
          color: white; font-size: 14px; font-weight: 600; font-family: 'DM Sans', sans-serif;
          box-shadow: 0 4px 16px rgba(147,51,234,0.35); transition: all 0.2s;
        }
        .don-add-btn:hover { transform: translateY(-2px); box-shadow: 0 6px 22px rgba(147,51,234,0.5); }

        /* Form card */
        .don-form-card {
          background: rgba(168,85,247,0.07); border: 1px solid rgba(168,85,247,0.2);
          border-radius: 20px; padding: 28px; margin-bottom: 28px;
          animation: slideDown 0.3s ease;
        }
        @keyframes slideDown { from { opacity:0; transform:translateY(-10px); } to { opacity:1; transform:translateY(0); } }
        .don-form-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; color: #fff; margin-bottom: 20px; }
        .don-form-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 16px; margin-bottom: 20px; }
        @media(max-width:700px){ .don-form-grid { grid-template-columns: 1fr; } }
        .don-field label { display: block; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.4); text-transform: uppercase; letter-spacing: 0.8px; margin-bottom: 8px; }
        .don-field select, .don-field input {
          width: 100%; padding: 12px 14px; border-radius: 12px;
          background: rgba(255,255,255,0.06); border: 1.5px solid rgba(255,255,255,0.1);
          color: #fff; font-size: 14px; font-family: 'DM Sans', sans-serif; outline: none;
          transition: all 0.2s;
        }
        .don-field select option { background: #1a0030; color: #fff; }
        .don-field select:focus, .don-field input:focus { border-color: #a855f7; background: rgba(168,85,247,0.1); box-shadow: 0 0 0 3px rgba(168,85,247,0.15); }
        .don-field input::placeholder { color: rgba(255,255,255,0.2); }
        .don-form-actions { display: flex; gap: 12px; }
        .don-submit-btn {
          padding: 12px 28px; border-radius: 12px; border: none; cursor: pointer;
          background: linear-gradient(135deg, #9333ea, #ec4899);
          color: white; font-size: 14px; font-weight: 600; font-family: 'DM Sans', sans-serif;
          transition: all 0.2s; box-shadow: 0 4px 16px rgba(147,51,234,0.3);
        }
        .don-submit-btn:hover { transform: translateY(-1px); filter: brightness(1.08); }
        .don-cancel-btn {
          padding: 12px 22px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1);
          background: transparent; color: rgba(255,255,255,0.5); font-size: 14px;
          cursor: pointer; font-family: 'DM Sans', sans-serif; transition: all 0.2s;
        }
        .don-cancel-btn:hover { border-color: rgba(255,255,255,0.25); color: rgba(255,255,255,0.8); }

        /* Info box */
        .don-info {
          padding: 16px 20px; border-radius: 14px; margin-bottom: 24px;
          background: rgba(99,102,241,0.08); border: 1px solid rgba(99,102,241,0.2);
          font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.6;
        }
        .don-info strong { color: rgba(255,255,255,0.8); }

        /* Stats */
        .don-stats { display: flex; gap: 14px; margin-bottom: 28px; flex-wrap: wrap; }
        .don-stat {
          flex: 1; min-width: 130px; padding: 18px 20px; border-radius: 16px;
          background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07);
          text-align: center;
        }
        .don-stat-num { font-family: 'Syne', sans-serif; font-size: 28px; font-weight: 800; color: #fff; }
        .don-stat-label { font-size: 12px; color: rgba(255,255,255,0.35); margin-top: 4px; }
        .don-stat.purple { border-color: rgba(168,85,247,0.25); background: rgba(168,85,247,0.07); }
        .don-stat.pink { border-color: rgba(236,72,153,0.25); background: rgba(236,72,153,0.07); }

        /* Table card */
        .don-table-card {
          background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07);
          border-radius: 18px; padding: 22px; backdrop-filter: blur(12px);
        }
        .don-table-title { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; color: rgba(255,255,255,0.85); margin-bottom: 18px; }
        .don-table { width: 100%; border-collapse: collapse; font-size: 13px; }
        .don-table th { text-align: left; padding: 10px 14px; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; border-bottom: 1px solid rgba(255,255,255,0.06); }
        .don-table td { padding: 14px 14px; color: rgba(255,255,255,0.65); border-bottom: 1px solid rgba(255,255,255,0.04); vertical-align: middle; }
        .don-table tr:last-child td { border-bottom: none; }
        .don-table tr:hover td { background: rgba(168,85,247,0.05); color: rgba(255,255,255,0.9); }
        .don-badge { display: inline-block; padding: 4px 12px; border-radius: 8px; font-size: 11px; font-weight: 600; }
        .don-badge-blood { background: rgba(168,85,247,0.15); color: #c084fc; }
        .don-badge-in { background: rgba(34,197,94,0.12); color: #4ade80; }
        .don-empty { text-align: center; padding: 60px 20px; }
        .don-empty-icon { font-size: 48px; margin-bottom: 12px; }
        .don-empty-text { font-size: 15px; color: rgba(255,255,255,0.3); margin-bottom: 6px; }
        .don-empty-sub { font-size: 13px; color: rgba(255,255,255,0.18); }
      `}</style>

      <div className="don-page">
        <div className="don-top">
          <div>
            <div className="don-title">
              My <span>Donations</span> 🩸
            </div>
            <div className="don-subtitle">
              Track every time you've saved a life
            </div>
          </div>
          <button
            className="don-add-btn"
            onClick={() => setShowForm(!showForm)}
          >
            {showForm ? "✕ Cancel" : "+ Record Donation"}
          </button>
        </div>

        {/* Record donation form */}
        {showForm && (
          <div className="don-form-card">
            <div className="don-form-title">📋 Log Your Blood Donation</div>
            <div className="don-form-grid">
              <div className="don-field">
                <label>Blood Group</label>
                <select
                  value={bloodGroup}
                  onChange={(e) => setBloodGroup(e.target.value)}
                >
                  <option value="">Select blood group</option>
                  {bloodGroups.map((bg) => (
                    <option key={bg} value={bg}>
                      {bg}
                    </option>
                  ))}
                </select>
              </div>
              <div className="don-field">
                <label>Quantity (ML)</label>
                <input
                  type="number"
                  placeholder="e.g. 450"
                  value={quantity}
                  onChange={(e) => setQuantity(e.target.value)}
                />
              </div>
              <div className="don-field">
                <label>Organisation Email</label>
                <input
                  type="email"
                  placeholder="blood bank email"
                  value={orgEmail}
                  onChange={(e) => setOrgEmail(e.target.value)}
                />
              </div>
            </div>
            <div className="don-form-actions">
              <button
                className="don-submit-btn"
                onClick={handleSubmit}
                disabled={submitting}
              >
                {submitting ? "Saving..." : "Submit Donation →"}
              </button>
              <button
                className="don-cancel-btn"
                onClick={() => setShowForm(false)}
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {/* Info */}
        <div className="don-info">
          💡 <strong>How it works:</strong> After physically donating blood at a
          camp or blood bank, come here and click{" "}
          <strong>"Record Donation"</strong> to log it. Enter your blood group,
          the amount donated (usually 350–450 ML), and the email of the
          organisation/blood bank you donated to.
        </div>

        {/* Stats */}
        <div className="don-stats">
          <div className="don-stat purple">
            <div className="don-stat-num">{data.length}</div>
            <div className="don-stat-label">Total Donations</div>
          </div>
          <div className="don-stat pink">
            <div className="don-stat-num">{data.length * 3}</div>
            <div className="don-stat-label">Lives Potentially Saved</div>
          </div>
          <div className="don-stat">
            <div className="don-stat-num">
              {data.reduce((sum, r) => sum + (Number(r.quantity) || 0), 0)}
            </div>
            <div className="don-stat-label">Total ML Donated</div>
          </div>
        </div>

        {/* Donations table */}
        <div className="don-table-card">
          <div className="don-table-title">📅 Donation History</div>
          {data.length === 0 ? (
            <div className="don-empty">
              <div className="don-empty-icon">🩸</div>
              <div className="don-empty-text">No donations recorded yet</div>
              <div className="don-empty-sub">
                Click "Record Donation" above after your first donation!
              </div>
            </div>
          ) : (
            <table className="don-table">
              <thead>
                <tr>
                  <th>Blood Group</th>
                  <th>Type</th>
                  <th>Quantity</th>
                  <th>Organisation</th>
                  <th>Date & Time</th>
                </tr>
              </thead>
              <tbody>
                {data.map((record) => (
                  <tr key={record._id}>
                    <td>
                      <span className="don-badge don-badge-blood">
                        {record.bloodGroup}
                      </span>
                    </td>
                    <td>
                      <span className="don-badge don-badge-in">Donated</span>
                    </td>
                    <td>{record.quantity} ML</td>
                    <td>{record.email || "—"}</td>
                    <td>
                      {moment(record.createdAt).format("DD MMM YYYY, hh:mm A")}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default Donation;
